changeSet.sql:
INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.document_aspects ON CONFLICT (tenant_id, name) DO NOTHING;
INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.aspect_extraction_queue ON CONFLICT (tenant_id, name) DO NOTHING;
INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.topics ON CONFLICT (tenant_id, name) DO NOTHING;
INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.taxonomy_meta ON CONFLICT (tenant_id, name) DO NOTHING;
INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.document_highlights WHERE collection IS NOT NULL AND collection != '' ON CONFLICT (tenant_id, name) DO NOTHING;
